{"command":"cat > /tmp/naga_binding_array_repro.sh <<'EOF'
#!/usr/bin/env bash
repo=/workspace/wgpu
tmp=$(mktemp -d)
trap 'rm -rf "$tmp"' EXIT
cat > "$tmp/no_enable.wgsl" <<'WGSL'
struct Buffer {
    value: u32,
}

@group(0) @binding(0)
var<storage> storage_array: binding_array<Buffer, 10>;

@compute @workgroup_size(1)
fn main() {
}
WGSL
cat > "$tmp/with_enable.wgsl" <<'WGSL'
enable wgpu_binding_array;

struct Buffer {
    value: u32,
}

@group(0) @binding(0)
var<storage> storage_array: binding_array<Buffer, 10>;

@compute @workgroup_size(1)
fn main() {
}
WGSL
cat > "$tmp/alias_with_enable.wgsl" <<'WGSL'
enable wgpu_binding_array;

struct Buffer {
    value: u32,
}

alias StorageArray = binding_array<Buffer, 4>;

@group(0) @binding(0)
var<storage> storage_array: StorageArray;

@compute @workgroup_size(1)
fn main() {
}
WGSL
fail=0
cd "$repo" || exit 2
run_naga() {
    cargo run -q -p naga-cli -- --capabilities "$1" "$2"
}
if run_naga all "$tmp/no_enable.wgsl" >"$tmp/no_enable.out" 2>&1; then
    echo "BUG: binding_array without enable was accepted"
    fail=1
else
    if grep -q "wgpu_binding_array" "$tmp/no_enable.out"; then
        echo "OK: binding_array without enable was rejected with wgpu_binding_array diagnostic"
    else
        echo "ERROR: binding_array without enable was rejected, but not for wgpu_binding_array"
        cat "$tmp/no_enable.out"
        fail=1
    fi
fi
if run_naga all "$tmp/with_enable.wgsl" >"$tmp/with_enable.out" 2>&1; then
    echo "OK: binding_array with enable was accepted"
else
    echo "ERROR: binding_array with enable was rejected"
    cat "$tmp/with_enable.out"
    fail=1
fi
if run_naga storage_buffer_binding_array "$tmp/with_enable.wgsl" >"$tmp/storage_cap.out" 2>&1; then
    echo "OK: wgpu_binding_array is supported by a specific binding-array capability"
else
    echo "ERROR: storage-buffer binding-array capability did not support enable directive"
    cat "$tmp/storage_cap.out"
    fail=1
fi
if run_naga none "$tmp/with_enable.wgsl" >"$tmp/no_caps.out" 2>&1; then
    echo "ERROR: wgpu_binding_array was accepted with no binding-array capabilities"
    fail=1
else
    if grep -q "extension is not supported" "$tmp/no_caps.out"; then
        echo "OK: wgpu_binding_array enable is rejected when no binding-array capability is available"
    else
        echo "ERROR: no-capability rejection did not report unsupported extension"
        cat "$tmp/no_caps.out"
        fail=1
    fi
fi
if run_naga all "$tmp/alias_with_enable.wgsl" >"$tmp/alias.out" 2>&1; then
    echo "OK: binding_array aliases work when enabled"
else
    echo "ERROR: binding_array alias with enable was rejected"
    cat "$tmp/alias.out"
    fail=1
fi
exit "$fail"
EOF
chmod +x /tmp/naga_binding_array_repro.sh
/tmp/naga_binding_array_repro.sh; printf 'exit=%s\n' $?","timeout":120,"security_risk":"MEDIUM","summary":"Add and run reproduction edge cases"}

